import { countryOptions, regionOptions } from '@constants';
import { useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { FormAddressControlProps } from '../AddressControl';
import { getFieldNames } from '../AddressControl/getFieldNames';
import { FormInputControl } from '../FormInputControl';
import { FormSelectControl } from '../SelectControl';
import { getRegionLabel } from './helpers';

type Props = {
  allowedCountries?: FormAddressControlProps['allowedCountries'];
  cityLabel?: string;
  countryLabel?: string;
  fieldPrefix: string | undefined;
  fieldPrefixDelimiter: string | undefined;
  isRequired?: boolean | undefined;
  stateLabel?: string;
};

export const FormCityStateInput = ({
  allowedCountries,
  cityLabel,
  countryLabel,
  fieldPrefix,
  fieldPrefixDelimiter,
  isRequired,
  stateLabel,
}: Props) => {
  const { t } = useTranslation('formControls');
  const { getValues, setValue, watch } = useFormContext();
  const { fieldCity, fieldCountry, fieldRegion } = getFieldNames(fieldPrefix, fieldPrefixDelimiter);

  const country = watch(fieldCountry);

  const allowedCountryOptions = useMemo(() => {
    return allowedCountries
      ? countryOptions.filter(({ value }) => allowedCountries.includes(value))
      : countryOptions;
  }, [allowedCountries]);

  useEffect(() => {
    if (allowedCountryOptions.length === 1) {
      const countryCode = allowedCountryOptions[0].value.toUpperCase();

      if (getValues(fieldCountry) !== countryCode) {
        setValue(fieldCountry, allowedCountryOptions[0].value.toUpperCase());
      }
    }
  }, [allowedCountryOptions, fieldCountry, getValues, setValue]);

  const countryRegions = useMemo(() => {
    if (country) {
      return regionOptions[country.toLowerCase()] ?? [];
    } else {
      return [];
    }
  }, [country]);

  return (
    <div className="flex flex-col gap-2">
      <div className="flex flex-row gap-2">
        <FormInputControl
          inputGroupProps={{
            gridColumnEnd: { base: 3, md: 2 },
            gridColumnStart: 1,
          }}
          isRequired={isRequired}
          label={cityLabel || t('formAddressControl.city')}
          name={fieldCity}
          placeholder="New Orleans"
        />
        {!countryRegions.length ? (
          <FormInputControl
            isRequired={isRequired}
            label={stateLabel || getRegionLabel(country, t)}
            name={fieldRegion}
            placeholder="LA"
          />
        ) : (
          <FormSelectControl
            isRequired={isRequired}
            label={stateLabel || getRegionLabel(country, t)}
            name={fieldRegion}
            options={countryRegions}
            placeholder="-"
          />
        )}
      </div>
      {allowedCountryOptions.length > 1 ? (
        <FormSelectControl
          isRequired={isRequired}
          label={countryLabel || t('formAddressControl.country')}
          name={fieldCountry}
          options={allowedCountryOptions}
          placeholder="-"
        />
      ) : null}
    </div>
  );
};

