import { TFunction } from 'react-i18next';

export const getRegionLabel = (
  countryCode: string | undefined = '',
  t: TFunction<'formControls'>
): string => {
  const code = countryCode?.toLowerCase();
  switch (code) {
    case 'us':
      return t('formAddressControl.state');
    case 'ca':
      return t('formAddressControl.province');
    default:
      return t('formAddressControl.state');
  }
};

export const getPostalCodeLabel = (
  countryCode: string | undefined = '',
  t: TFunction<'formControls'>
): string => {
  const code = countryCode?.toLowerCase();
  switch (code) {
    case 'us':
      return t('formAddressControl.zip');
    case 'ca':
      return t('formAddressControl.postalCode');
    default:
      return t('formAddressControl.postalCode');
  }
};

